/**
 * @summary List hadiths in a collection
 */
export const getListHadithsUrl = (
  collectionId: string,
  params?: ListHadithsParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/hadith/collections/${collectionId}/hadiths?${stringifiedParams}`
    : `/api/hadith/collections/${collectionId}/hadiths`;
};

export const listHadiths = async (
  collectionId: string,
  params?: ListHadithsParams,
  options?: RequestInit,
): Promise<HadithListResponse> => {
  return customFetch<HadithListResponse>(
    getListHadithsUrl(collectionId, params),
    {
      ...options,
      method: "GET",
    },
  );
};

export const getListHadithsQueryKey = (
  collectionId: string,
  params?: ListHadithsParams,
) => {
  return [
    `/api/hadith/collections/${collectionId}/hadiths`,
    ...(params ? [params] : []),
  ] as const;
};

